module top_module(
  input clk,
  input reset,
  input [15:0] A,
  input [15:0] B,
  output [15:0] C
);reg [15:0] unused_sum;

  always @(posedge clk) begin
    if (reset) begin
      unused_sum <= 16'b0;
    end else begin
      unused_sum <= A + B;
    end
  end

  assign C = unused_sum;

endmodule
